import { callMcpSkill } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  // Step 1: Single broad discovery call (shortlist-first, no parallel same-endpoint)
  const search = await callMcpSkill({
    toolId,
    toolName: "search_markets",
    args: { query: "Iran boots ground troops US military invasion war allied", limit: 50, status: "all" }
  });

  const candidates = Array.isArray(search?.results) ? search.results : [];

  // Step 2: Deterministic semantic targeting — rank against explicit legs
  // Leg A: Direct instrument — boots on ground / ground troop intervention
  const directLeg = pickTopSemanticCandidates({
    target: "US or allied boots on the ground military intervention in Iran",
    candidates,
    requiredTerms: ["iran", "ground", "boots", "troops", "invasion", "military intervention"],
    avoidTerms: ["airstrike", "strike only", "bombing only", "missile", "sanctions", "nuclear deal"],
    limit: 5,
  });

  // Leg B: Related escalation markets (broader Iran military conflict, as context for risk-off)
  const escalationLeg = pickTopSemanticCandidates({
    target: "Iran broader military conflict escalation US involvement",
    candidates,
    requiredTerms: ["iran", "war", "military", "conflict", "attack"],
    avoidTerms: ["sanctions", "diplomatic", "nuclear deal", "election", "protest"],
    limit: 5,
  });

